import React, { useState, useEffect } from 'react';

const AddTourFilters = () => {
  const [filters, setFilters] = useState({});

  useEffect(() => {
    fetch('/api/filters.json')
      .then(res => res.json())
      .then(data => setFilters(data))
      .catch(() => {
        // Fallback
        setFilters({
          amenities: {
            tv: false,
            slippers: false,
            shower: false,
            airConditioner: false,
            miniBar: false,
            phone: false,
            heating: false,
            wifi: false
          }
        });
      });
  }, []);

  const toggleFilter = (category, key) => {
    setFilters(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [key]: !prev[category][key]
      }
    }));
  };

  // Отправляем фильтры в URL
  useEffect(() => {
    const params = new URLSearchParams();
    Object.entries(filters).forEach(([category, items]) => {
      Object.entries(items).forEach(([key, value]) => {
        if (value) params.set(`${category}_${key}`, 'true');
      });
    });
    window.history.replaceState({}, '', `?${params.toString()}`);
  }, [filters]);

  return (
    <div className="AddTourFilters" style={{
      width: '280px',
      padding: '20px',
      background: '#f8f9fa',
      borderRadius: '8px',
      marginRight: '20px'
    }}>
      <h3 style={{ marginTop: 0, color: '#333' }}>Фильтры по удобствам</h3>
      
      <div style={{ marginBottom: '20px' }}>
        {Object.entries(filters.amenities || {}).map(([key, value]) => {
          const labels = {
            tv: 'Телевизор',
            slippers: 'Тапочки', 
            shower: 'Душ',
            airConditioner: 'Кондиционер',
            miniBar: 'Мини-бар',
            phone: 'Телефон',
            heating: 'Отопление',
            wifi: 'Wi-Fi'
          };
          
          return (
            <label key={key} style={{ 
              display: 'block', 
              marginBottom: '12px',
              cursor: 'pointer',
              fontSize: '14px'
            }}>
              <input
                type="checkbox"
                checked={value}
                onChange={() => toggleFilter('amenities', key)}
                style={{ marginRight: '8px' }}
              />
              {labels[key]}
            </label>
          );
        })}
      </div>

      <button 
        style={{
          width: '100%',
          padding: '10px',
          background: '#c50076',
          color: 'white',
          border: 'none',
          borderRadius: '4px',
          cursor: 'pointer'
        }}
        onClick={() => setFilters({ amenities: { tv: false, slippers: false, shower: false, airConditioner: false, miniBar: false, phone: false, heating: false, wifi: false } })}
      >
        Сбросить
      </button>
    </div>
  );
};

export default AddTourFilters;
